const body = $input.first().json.body || $input.first().json;

const user_id      = body.user_id      || null;
const workspace_id = body.workspace_id || null;
const full_name    = body.full_name    || body.name || null;
const idea         = body.idea         || null;
const stage        = body.stage        || 'Idea';
const challenge    = body.challenge    || null;
const lane         = body.lane         || 'Idea';

if (!user_id)      throw new Error('Missing: user_id');
if (!workspace_id) throw new Error('Missing: workspace_id');
if (!idea)         throw new Error('Missing: idea');
if (!challenge)    throw new Error('Missing: challenge');

const ALLOWED_LANES = ['Idea', 'Offer', 'Customer', 'Systems'];
const safe_lane = ALLOWED_LANES.includes(lane) ? lane : 'Idea';

return [{
  json: {
    user_id,
    workspace_id,
    full_name,
    idea,
    stage,
    challenge,
    lane: safe_lane,
    raw_answers: { full_name, idea, stage, challenge },
    now: new Date().toISOString()
  }
}];

const upsertResult = $('Upsert workspace_intake').item.json;
return [{
  json: {
    ok: true,
    workspace_id: $('Parse & Validate').item.json.workspace_id,
    lane: $('Parse & Validate').item.json.lane,
    intake_saved: true
  }
}];
